  useEffect(() => {
    if (!selected) return;
    getChildFees(selected.id).then(d => setFees(Array.isArray(d) ? d : [])).catch(console.error);
  }, [selected]);

  const totalPaid   = fees.filter(f => f.status === "PAID").reduce((s, f) => s + Number(f.paidAmount || f.amount || 0), 0);
